    ensures
        res.is_bst(),
        res.view() =~= tree.view(),
        // Postcondition: If v was in the tree, it is now at the root.
        tree.view().contains(v) ==> res.val == v,
        // Postcondition: If v was NOT in the tree, the new root is 
        // the last node accessed during the search (predecessor or successor).
        !tree.view().contains(v) ==> res.view().contains(res.val),
