        assert(forall |x| #[trigger] rl_view.contains(x) ==> x < v_r);
        assert(forall |x| #[trigger] root_left_view.contains(x) ==> x < v_root);

        assert(forall |x| #[trigger] new_root_view.contains(x) ==> x < v_r);

        r.left = Some(root);
        assert(r.is_bst());
        assert(r.view() =~= old_root_view);
        r
    }
